d-078d353\"]},\"paragraph\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"T\\u00f4i hi\\u1ec7n l\\u00e0 sinh vi\\u00ean n\\u0103m 3 ng\\u00e0nh C\\u00f4ng ngh\\u1ec7 th\\u00f4ng tin. T\\u00f4i y\\u00eau th\\u00edch thi\\u1ebft k\\u1ebf website, l\\u1eadp tr\\u00ecnh web v\\u00e0 kh\\u00e1m ph\\u00e1 c\\u00f4ng ngh\\u1ec7 m\\u1edbi. Hi\\u1ec7n t\\u1ea1i t\\u00f4i \\u0111ang h\\u1ecdc WordPress,trong t\\u01b0\\u01a1ng lai, t\\u00f4i mong mu\\u1ed1n tr\\u1edf th\\u00e0nh m\\u1ed9t Web Developer chuy\\u00ean nghi\\u1ec7p, c\\u00f3 kh\\u1ea3 n\\u0103ng thi\\u1ebft k\\u1ebf v\\u00e0 x\\u00e2y d\\u1ef1ng c\\u00e1c website hi\\u1ec7n \\u0111\\u1ea1i, t\\u1ed1i \\u01b0u v\\u00e0 th\\u00e2n thi\\u1ec7n v\\u1edbi ng\\u01b0\\u1eddi d\\u00f9ng.T\\u00f4i \\u0111ang t\\u1eadp trung h\\u1ecdc t\\u1eadp c\\u00e1c c\\u00f4ng ngh\\u1ec7 nh\\u01b0 HTML, CSS, JavaScript, PHP, Laravel, ReactJS v\\u00e0 WordPress \\u0111\\u1ec3 n\\u00e2ng cao k\\u1ef9 n\\u0103ng chuy\\u00ean m\\u00f4n.M\\u1ee5c ti\\u00eau c\\u1ee7a t\\u00f4i l\\u00e0 \\u0111\\u01b0\\u1ee3c l\\u00e0m vi\\u1ec7c trong m\\u00f4i tr\\u01b0\\u1eddng c\\u00f4ng ngh\\u1ec7 n\\u0103ng \\u0111\\u1ed9ng, tham gia c\\u00e1c d\\u1ef1 \\u00e1n th\\u1ef1c t\\u1ebf v\\u00e0 kh\\u00f4ng ng\\u1eebng ph\\u00e1t tri\\u1ec3n b\\u1ea3n th\\u00e2n.\"},\"children\":[]}}},\"elements\":[],\"widgetType\":\"e-paragraph\",\"styles\":{\"e-3259bfd-078d353\":{\"id\":\"e-3259bfd-078d353\",\"label\":\"local\",\"type\":\"class\",\"variants\":[{\"meta\":{\"breakpoint\":\"desktop\",\"state\":null},\"props\":{\"font-family\":{\"$$type\":\"string\",\"value\":\"Times New Roman\"},\"font-weight\":{\"$$type\":\"string\",\"value\":\"400\"},\"font-size\":{\"$$type\":\"size\",\"value\":{\"size\":18,\"unit\":\"px\"}},\"color\":{\"$$type\":\"color\",\"value\":\"#475a69\"}},\"custom_css\":null}]}},\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"}],\"isInner\":true}],\"isInner\":false}]'),
