(97, 1, '2026-04-13 03:23:58', '2026-04-13 03:23:58', '<h2 \n		data-interaction-id=\"48531b8\" \n		class=\"e-48531b8-26d1e6a e-heading-base\" \n	>\n			Học vấn\n		</h2>\n								<p data-interaction-id=\"8f022ad\"  >\n								Sinh viên năm 3 ngành Công nghệ Thông tin<br>Trường Đại học / Cao đẳng: Đại học Tây Nguyên(TTN)<br>Thời gian học: 2023 - 2027<br>Định hướng: Lập trình Web Developer / Fullstack Developer Phiên\n					</p>\n				Kĩ năng của tôi			\n				HTML/CSS\n									68%\n				WordPress\n									75%\n				JavaScript\n									50%\n				PHP\n									59%', 'Kỹ năng &amp; học vấn', '', 'inherit', 'closed', 'closed', '', '43-revision-v1', '', '', '2026-04-13 03:23:58', '2026-04-13 03:23:58', '', 43, 'http://localhost/wordpress/?p=97', 0, 'revision', '', 0),
